solution_code:
#include <iostream>
#include <memory>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        auto first = std::make_unique<int>(val);
        std::unique_ptr<int> second = std::move(first);
        std::cout << "Transferred: " << *second << "\n";
    }
    return 0;
}

